import React from "react";
import matillionlogo from '../assets/images/matillion_logo.png';
import '../assets/styles/Project.scss';

function Project() {
    return(
    <div className="projects-container" id="projects">
        <h1>Personal Projects</h1>
        <div className="projects-grid">
            <div className="project" style={{ backgroundColor:"#F8F9FA" }}>
                <a href="https://pypi.org/project/pymatillion/" target="_blank" rel="noreferrer"><img src={matillionlogo} className="zoom" alt="thumbnail" width="75%"/></a>
                <a href="https://pypi.org/project/pymatillion/" target="_blank" rel="noreferrer"><h2>Open-Source Python Library</h2></a>
                <p>Published an open-source Python library to PyPI for interfacing with the Matillion REST API and automating tasks</p>
            </div>
        </div>
    </div>
    );
}

export default Project;
